// 第 9/13 步 onRefresh()
@Override
protected void onRefresh() {
    super.onRefresh();
    try {
        createWebServer();
    } catch (Throwable ex) { ... }
}

private void createWebServer() {
    WebServer webServer = this.webServer;
    ServletContext servletContext = this.getServletContext();
    if (webServer == null && servletContext == null) {
        ServletWebServerFactory factory = getWebServerFactory();
        this.webServer = factory.getWebServer(new ServletContextInitializer[]{...});
    }
    initPropertySources();
}

protected ServletWebServerFactory getWebServerFactory() {
    String[] beanNames = getBeanFactory()
        .getBeanNamesForType(ServletWebServerFactory.class);
    return getBeanFactory().getBean(beanNames[0], ServletWebServerFactory.class);
}

public WebServer getWebServer(ServletContextInitializer... initializers) {
    Tomcat tomcat = new Tomcat();
    File baseDir = (this.baseDirectory != null) ? this.baseDirectory : createTempDir("tomcat");
    tomcat.setBaseDir(baseDir.getAbsolutePath());
    Connector connector = new Connector(this.protocol);
    tomcat.getService().addConnector(connector);
    customizeConnector(connector);
    tomcat.setConnector(connector);
    tomcat.getHost().setAutoDeploy(false);
    configureEngine(tomcat.getEngine());
    return getTomcatWebServer(tomcat);
}

private void prepareContext(Host host, ServletContext servletContext) {
    TomcatEmbeddedContext ctx = new TomcatEmbeddedContext();
    ctx.setName("TomcatEmbeddedContext");
    ctx.setParentClassLoader(this.getClass().getClassLoader());
    // 注册 ServletContainerInitializer
    ServletContextInitializer[] initializers = ...;
    for (ServletContextInitializer initializer : initializers) {
        initializer.onStartup(servletContext);
    }
    host.addChild(ctx);
}

public class TomcatWebServer implements WebServer {
    public TomcatWebServer(Tomcat tomcat, boolean autoStart) {
        this.tomcat = tomcat;
        this.autoStart = autoStart;
        initialize();
    }
    private void initialize() throws WebServerException {
        synchronized (this.monitor) {
            addInstanceIdToEngineName();
            Context context = findContext();
            context.addLifecycleListener(event -> {
                if (event.getType().equals(Lifecycle.START_EVENT)) { ... }
            });
            // 启动 Tomcat
            this.tomcat.start();
        }
    }
}

public class Connector extends LifecycleMBeanBase {
    @Override
    protected void startInternal() throws LifecycleException {
        ProtocolHandler protocolHandler = this.protocolHandler;
        // NIO / NIO2 / APR
        protocolHandler.start();  // 启动 NioEndpoint
    }
}

